function Modal({ card, onClose }) {
  useEffect(() => {
    if (card) {
      document.body.style.overflow = 'hidden'
    }
    return () => { document.body.style.overflow = '' }
  }, [card])
  const handleClose = () => { onClose() }
  if (!card) return null
  return (
    <div onClick={handleClose} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.8)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:'24px', backdropFilter:'blur(8px)', touchAction:'none' }}
      onTouchMove={e => e.stopPropagation()}>
      <div onClick={e => e.stopPropagation()} style={{ background:'#0d0d12', border:'1px solid rgba(193,112,232,0.3)', borderRadius:'20px', padding:'40px', maxWidth:'580px', width:'100%', position:'relative', boxShadow:'0 0 60px rgba(193,112,232,0.15)', maxHeight:'85vh', overflowY:'auto', WebkitOverflowScrolling:'touch' }} onTouchMove={e => e.stopPropagation()}>
        <button onClick={handleClose} style={{ position:'absolute', top:'16px', right:'16px', background:'rgba(255,255,255,0.08)', border:'none', borderRadius:'50%', width:'32px', height:'32px', color:'#fff', fontSize:'18px', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center' }}>×</button>
        <div style={{ width:'4px', height:'32px', background:V, borderRadius:'2px', marginBottom:'16px' }}/>
        <h3 style={{ fontSize:'24px', fontWeight:800, color:'#fff', marginBottom:'24px', lineHeight:1.3 }}>{card.title}</h3>
        {card.incluye && <>
          <div style={{ marginBottom:'16px' }}>
            <p style={{ fontSize:'11px', fontWeight:700, color:V, letterSpacing:'0.15em', textTransform:'uppercase', marginBottom:'8px' }}>¿Qué incluye?</p>
            <p style={{ color:'rgba(255,255,255,0.7)', fontSize:'15px', lineHeight:1.75 }}>{card.incluye}</p>
          </div>
          <div style={{ marginBottom:'16px' }}>
            <p style={{ fontSize:'11px', fontWeight:700, color:V, letterSpacing:'0.15em', textTransform:'uppercase', marginBottom:'8px' }}>¿Para quién es?</p>
            <p style={{ color:'rgba(255,255,255,0.7)', fontSize:'15px', lineHeight:1.75 }}>{card.quien}</p>
          </div>
          <div style={{ background:'rgba(193,112,232,0.08)', border:'1px solid rgba(193,112,232,0.2)', borderRadius:'12px', padding:'16px 20px' }}>
            <p style={{ fontSize:'11px', fontWeight:700, color:V, letterSpacing:'0.15em', textTransform:'uppercase', marginBottom:'8px' }}>✦ Beneficio clave</p>
            <p style={{ color:'rgba(255,255,255,0.85)', fontSize:'15px', lineHeight:1.75, fontWeight:500 }}>{card.beneficio}</p>
          </div>
        </>}
        {card.desc && <>
          <p style={{ color:'rgba(255,255,255,0.7)', fontSize:'15px', lineHeight:1.75, marginBottom:'16px' }}>{card.desc}</p>
          {card.ej && (
            <div style={{ background:'rgba(193,112,232,0.08)', border:'1px solid rgba(193,112,232,0.2)', borderRadius:'12px', padding:'16px 20px' }}>
              <p style={{ fontSize:'11px', fontWeight:700, color:V, letterSpacing:'0.15em', textTransform:'uppercase', marginBottom:'8px' }}>💡 Ejemplo simple</p>
              <p style={{ color:'rgba(255,255,255,0.7)', fontSize:'14px', lineHeight:1.7 }}>{card.ej}</p>
            </div>
          )}
        </>}
        <a href="https://wa.link/fj0ujx" target="_blank" rel="noopener noreferrer"
          style={{ display:'inline-flex', alignItems:'center', gap:'8px', marginTop:'28px', padding:'12px 28px', background:V, borderRadius:'12px', color:'#fff', fontWeight:700, fontSize:'15px', textDecoration:'none' }}>
          Consultá por este servicio →
        </a>
      </div>
    </div>
  )
}

function SvcCard({ title, onClick }) {
  const [hovered, setHovered] = useState(false)
  return (
    <div className="svc-card" style={{ cursor:'pointer', display:'flex', flexDirection:'column', justifyContent:'space-between', minHeight:'140px' }}
      onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)} onClick={onClick}>
      <div>
        <div className="svc-title">{title}</div>
        <div className="svc-div"/>
      </div>
      <button style={{ display:'inline-flex', alignItems:'center', gap:'6px', background:'none', border:'none', color: hovered ? V : 'rgba(255,255,255,0.4)', fontSize:'13px', fontWeight:600, cursor:'pointer', fontFamily:'inherit', padding:0, transition:'all 0.3s', marginTop:'12px' }}>
        Ver más <span style={{ transition:'transform 0.3s', transform: hovered ? 'translateX(4px)' : 'translateX(0)' }}>→</span>
      </button>
    </div>
  )
}

